[Form]
public class ETGElevatorReceiptForm extends FormRun
{
}

/// <summary>
/// Abhinav - 14-1-26
/// </summary>
public void initValue()
{
    ttsbegin;
    NumberSequenceReference numberSequenceReference;
    numberSequenceReference = NumberSeqReference::findReference(extendedTypeNum(ETGElevatorReceiptNumber));
    if (numberSequenceReference)
    {
        ETGElevatorReceiptTable.ElevatorReceiptNumber = NumberSeq::newGetNum(numberSequenceReference).num();
    }
    ttscommit;
    super();
}

/// <summary>
///
/// </summary>
/// <returns></returns>
public int active()
{
    int ret;

    ret = super();

    Confirm.enabled(ETGElevatorReceiptTable.ETGElevatorReceiptStatus == ETGElevatorReceiptStatus::Draft);
    ChangeRequest.enabled(ETGElevatorReceiptTable.ETGElevatorReceiptStatus == ETGElevatorReceiptStatus::Confirmed);

    CreateZeroValuePO.enabled(ETGElevatorReceiptTable.ETGElevatorReceiptStatus == ETGElevatorReceiptStatus::POCreated && ETGElevatorReceiptTable.PONumberInDefaultEntity && !ETGElevatorReceiptTable.ZeroValuePONumber);
    AmmendmentOfPO.enabled(ETGElevatorReceiptTable.ETGElevatorReceiptStatus == ETGElevatorReceiptStatus::Confirmed && !ETGElevatorReceiptTable.PONumberInDefaultEntity);

    if(ETGElevatorReceiptTable.ETGElevatorReceiptStatus == ETGElevatorReceiptStatus::Draft)
    {
        ETGElevatorReceiptTable_ds.allowEdit(true);
    }
    else
    {
        ETGElevatorReceiptTable_ds.allowEdit(false);
    }
    PrintReceipt.enabled(ETGElevatorReceiptTable.ETGElevatorReceiptStatus == ETGElevatorReceiptStatus::Confirmed || ETGElevatorReceiptTable.ETGElevatorReceiptStatus == ETGElevatorReceiptStatus::POCreated);
    ETGElevatorReceiptTable_ds.allowDelete(ETGElevatorReceiptStatus::Draft);

    //CS - BIN Qty Status activation - Abhinav
    PartList partList = new PartList(this.formRun());
    FormPartControl formpartcontrol = partList.getPartControlByFormName(formStr(ETGBinVolumeAvailableChartForm));
    formpartcontrol.visible(ETGCanadaParameters::find().EnableBinQtyStatus);

    if(ETGCanadaParameters::find().EnableBinQtyStatus)
    {
        InventDim inventdim,inventdimnew;
        ETGBinQtyVisualChartHelperClass::populateBinQtyChartData(inventdimnew,formpartcontrol);
    }
    //CE

    return ret;
}

/// <summary>
///
/// </summary>
public void executeQuery()
{
    this.query().dataSourceTable(tableNum(ETGElevatorReceiptTable)).sortClear();
    this.query().dataSourceTable(tableNum(ETGElevatorReceiptTable)).addSortField(fieldNum(ETGElevatorReceiptTable,ElevatorReceiptNumber),SortOrder::Descending);

    super();
}

/// <summary>
///
/// </summary>
public void clicked()
{
    super();

    ETGElevatorReceiptGrainItemTable etgElevatorReceiptGrainItemTable;

    select sum(GrainQty) from etgElevatorReceiptGrainItemTable
        where etgElevatorReceiptGrainItemTable.ElevatorReceiptNumber == ETGElevatorReceiptTable.ElevatorReceiptNumber;

    if(etgElevatorReceiptGrainItemTable.GrainQty != ETGElevatorReceiptTable.NetWeight)
    {
        throw error("@ETG_New:GrainQtySumValidation");
    }

    ETGElevatorReceiptTable.ETGElevatorReceiptStatus = ETGElevatorReceiptStatus::Confirmed;
    ETGElevatorReceiptTable_ds.research(true);
    ETGElevatorReceiptTable_ds.refresh();
}

/// <summary>
///
/// </summary>
public void clicked()
{
    super();

    ETGElevatorReceiptTable.ETGElevatorReceiptStatus = ETGElevatorReceiptStatus::Draft;
    ETGElevatorReceiptTable_ds.research(true);
    ETGElevatorReceiptTable_ds.refresh();
}

/// <summary>
///
/// </summary>
public void clicked()
{
    super();
    if(Box::okCancel('@ETG_New:CreateZeroValuePO',DialogButton::Cancel,'Confirm'))
    {
        NumberSeq                       numberSeq;
        Purchtable                      Purchtable;
        PurchLine                       PurchLine;
        //PurchFormLetter                 purchFormLetter;
        PurchFormLetter                 purchFormLetterCnf;
        PurchFormLetter_Invoice         purchFormLetterInv;
        PurchFormLetter_PackingSlip     purchFormLetterPsilp;
        AgreementLine                   _agreementLine;
        InventDim inventdimLoc;
        ETGElevatorReceiptTable         etgElevatorReceipt = ETGElevatorReceiptTable_ds.cursor();
        ETGScaleTicketTable             etgScaleTicketTable = ETGScaleTicketTable::findFromScaleTicketNumber(etgElevatorReceipt.scaleticketreferenceNumber);
        PurchAgreementHeader            purchAgreementHeader = PurchAgreementHeader::findByAgreementId(etgScaleTicketTable.RefPurchAgreementNum,ETGCanadaParameters::find().DefaultEntityForDocuments);
        VendTable                       vendTable = VendTable::findByDataAreaId(purchAgreementHeader.VendAccount,ETGCanadaParameters::find().DefaultEntityForDocuments);

        ttsbegin;
        ///Create purchTable
        numberSeq = NumberSeq::newGetNum(PurchParameters::numRefPurchId());
        //numberSeq.used();
        Purchtable.PurchId = numberSeq.num();
        Purchtable.initValue();
        purchTable.OrderAccount = purchAgreementHeader.VendAccount;
        purchTable.initFromVendTable(vendTable);
        purchTable.PurchaseType = PurchaseType::Purch;
        purchTable.ETGElevatorReceiptNumber       = etgElevatorReceipt.ElevatorReceiptNumber;
        if (!Purchtable.validateWrite())
        {
            throw Exception::Error;
        }
        Purchtable.DefaultDimension = purchAgreementHeader.DefaultDimension;
        Purchtable.insert();

        ///Create purchLine for grain received
        changeCompany(ETGCanadaParameters::find().DefaultEntityForDocuments)
        {
            select firstonly _agreementLine
                where _agreementLine.Agreement == purchAgreementHeader.RecId
                && _agreementLine.LineNumber == etgElevatorReceipt.AgreementLineNum;
        }

        ETGElevatorReceiptGrainItemTable etgElevatorReceiptGrainItemTable;

        while select etgElevatorReceiptGrainItemTable
            where etgElevatorReceiptGrainItemTable.ElevatorReceiptNumber == etgElevatorReceipt.ElevatorReceiptNumber
        {
            PurchLine.clear();
            PurchLine.PurchId = Purchtable.PurchId;
            PurchLine.ItemId = etgElevatorReceiptGrainItemTable.ItemId;
            PurchLine.initFromPurchTable(Purchtable);
            PurchLine.initFromInventTable(InventTable::find(PurchLine.ItemId));
            //purchLine.initFromAgreementLine(_agreementLine);
            PurchLine.PurchQty = etgElevatorReceiptGrainItemTable.GrainQty;
            PurchLine.PurchReceivedNow = PurchLine.PurchQty;

            InventTable InventTableItem;
            WMSLocation location;

            InventTableItem             = InventTable::find(etgElevatorReceiptGrainItemTable.ItemId);
            inventdimLoc.InventSizeId   = InventTableItem.StandardInventSizeId;
            inventdimLoc.InventColorId  = InventTableItem.StandardInventColorId;
            inventdimLoc.InventStyleId  = InventTableItem.StandardInventStyleId;
            inventdimLoc.configId       = InventTableItem.StandardConfigId;
            if(etgScaleTicketTable.PrimaryBIN)
            {
                //container binValues = str2con(etgScaleTicketTable.BIN,';');
                select firstonly location where location.wMSLocationId == etgScaleTicketTable.PrimaryBIN;
                InventLocation inventlocation   = InventLocation::find(location.inventLocationId);
                inventdimLoc.InventSiteId       = inventlocation.InventSiteId;
                inventdimLoc.InventLocationId   =  inventlocation.InventLocationId;
                inventdimLoc.wMSLocationId      = location.wMSLocationId;
            }
            else
            {
                inventdimLoc.InventSiteId       = ETGCanadaParameters::find().SiteForZeroValuePo;
                inventdimLoc.InventLocationId   =  ETGCanadaParameters::find().WareHouseForZeroValuePo;
                select firstonly location where location.inventLocationId == inventdimLoc.InventLocationId;
                inventdimLoc.wMSLocationId      = location.wMSLocationId;
            }
            InventDim inventdim = InventDim::findOrCreate(inventdimLoc);
            PurchLine.InventDimId = inventdim.inventDimId;
            PurchLine.PurchPrice = 0;
            PurchLine.QtyOrdered = PurchLine.PurchQty;
            PurchLine.DefaultDimension = _agreementLine.DefaultDimension;
            PurchLine.createLine(true, true, true, true, true, true);
        }

        ///Create dockage item purchline
        if(etgElevatorReceipt.DockageGrain)
        {
            this.createDockageItemLine(Purchtable,etgElevatorReceipt,etgScaleTicketTable,_agreementLine);
        }

        //create splits item purchLine
        this.createSplitsItemLine(Purchtable,etgElevatorReceipt,etgScaleTicketTable,_agreementLine);

        info(strfmt("@ETG_New:ZeroValuePOcreated",purchTable.PurchId));
        numberSeq.used();
        ttscommit;

        if(purchtable.DefaultDimension)
        {
            boolean                     isValid = true;
            boolean                     isValidLine;
            DimensionValidationStatus   dimensionValidationStatus;
            DimensionValidationStatus   dimensionValidationStatusLine;
            LedgerDimensionAccount      ledgerDimension;
            VendPostingProfile          postingprofile = purchtable.PostingProfile ? purchtable.PostingProfile : VendParameters::find().PostingProfile;

            ledgerDimension = LedgerDimensionFacade::serviceCreateLedgerDimension(VendLedgerAccounts::summaryLedgerDimension(purchtable.OrderAccount,postingprofile,true),purchtable.DefaultDimension);
            dimensionValidationStatus = LedgerDimensionValidationHelper::validateByTree(ledgerDimension, purchtable.DeliveryDate, true, true);

            if(dimensionValidationStatus == DimensionValidationStatus::Valid)
            {
                PurchLine purchLineLoc;

                while select purchLineLoc
                    where purchLineLoc.PurchId == purchtable.PurchId
                {
                    ledgerDimension = LedgerDimensionFacade::serviceCreateLedgerDimension(VendLedgerAccounts::summaryLedgerDimension(purchtable.OrderAccount,postingprofile,true),purchLineLoc.DefaultDimension);
                    dimensionValidationStatusLine = LedgerDimensionValidationHelper::validateByTree(ledgerDimension, purchtable.DeliveryDate, true, true);

                    if(dimensionValidationStatusLine == DimensionValidationStatus::Valid)
                    {
                        isValidLine = true;
                    }
                    else
                    {
                        isValidLine = false;
                        break;
                    }
                }
            }
            else
            {
                isValid = false;
            }

            if(isValid && isValidLine)
            {
                //Confirm purchase order
                try
                {
                    ttsbegin;
                    purchFormLetterCnf = PurchFormLetter::construct(DocumentStatus::PurchaseOrder);

                    purchFormLetterCnf.update(
                                    purchTable,
                                    strFmt('%1-%2', purchTable.PurchId, DateTimeUtil::getSystemDate(DateTimeUtil::getUserPreferredTimeZone())),
                                    SystemDateGet(),
                                    PurchUpdate::All,
                                    AccountOrder::None,
                                    NoYes::No,
                                    NoYes::No
                                );
                    ttscommit;
                }
                catch
                {
                    warning(strFmt("@ETG_New:ErrorInConfirmingPO",purchTable.PurchId));
                }
                Purchtable.reread();

                try
                {
                    ttsbegin;
                    InventTrans                 inventTrans;
                    InventTransWMS_Register     inventTransWMS_register;
                    TmpInventTransWMS           tmpInventTransWMS;

                    // Find the transaction and prepare registration
                    inventTrans = InventTrans::findTransId(PurchLine.InventTransId);
                    tmpInventTransWMS.initFromInventTrans(inventTrans);
                    tmpInventTransWMS.InventQty = PurchLine.PurchQty;
                    tmpInventTransWMS.insert();

                    // Execute registration
                    inventTransWMS_register = inventTransWMS_register::newStandard(tmpInventTransWMS);
                    inventTransWMS_register.updateInvent(PurchLine);

                    //POST GRN Purchase order
                    if (Purchtable.DocumentState == VersioningDocumentState::Confirmed)
                    {
                        purchFormLetterPsilp = PurchFormLetter::construct(DocumentStatus::PackingSlip);

                        purchFormLetterPsilp.update( Purchtable,
                                            strFmt("%1", Purchtable.PurchId),
                                            SystemDateGet(),
                                            PurchUpdate::All,
                                            AccountOrder::None,
                                            false,
                                            false);
                    }
                    ttscommit;
                }
                catch
                {
                    warning(strFmt("@ETG_New:ErrorInGRNPosting",purchTable.PurchId));
                }

                Purchtable.reread();

                try
                {
                    ttsbegin;
                    //Invoice purchase order
                    purchFormLetterInv = PurchFormLetter::construct(DocumentStatus::Invoice);
                    purchFormLetterInv.update(Purchtable,
                       "Inv-" + Purchtable.PurchId,
                       SystemDateGet(),
                PurchUpdate::PackingSlip,
                       AccountOrder::None,
                       NoYes::No,
                       NoYes::No);

                    ttscommit;

                    if (PurchTable::find(purchTable.PurchId).DocumentStatus == DocumentStatus::Invoice)
                    {
                        info(strfmt("@ETG_New:InvoiceJournalPosted",purchTable.PurchId));
                    }
                }
                catch
                {
                    warning(strFmt("@ETG_New:ErrorInInvoicingPO.",purchTable.PurchId));
                }
            }
            else
            {
                warning("Mandatory FD values are not available. Please update in PO and proceed with auto posting.");
            }
        }
        else
        {
            warning("FD values are not available in vendor master.Please update and proceed with auto posting.");
        }

        ETGElevatorReceiptTable.ETGElevatorReceiptStatus = ETGElevatorReceiptStatus::POCreated;
        ETGElevatorReceiptTable.ZeroValuePONumber = Purchtable.PurchId;
    }
    ETGElevatorReceiptTable_ds.research(true);
    ETGElevatorReceiptTable_ds.refresh();
}

/// <summary>
/// Create purchline for dockage item
/// </summary>
/// <param name = "Purchtable"></param>
/// <param name = "_agreementLine"></param>
/// <param name = "etgElevatorReceipt"></param>
public void createDockageItemLine(PurchTable Purchtable,ETGElevatorReceiptTable etgElevatorReceipt,ETGScaleTicketTable etgScaleTicketTable,AgreementLine _agreementLine)
{
    PurchLine PurchLine;
    InventDim inventdimLoc;
    PurchLine.PurchId = Purchtable.PurchId;

    PurchLine.initFromPurchTable(Purchtable);
    //purchLine.initFromAgreementLine(_agreementLine);
    PurchLine.ItemId    = etgElevatorReceipt.DockageGrain;
    PurchLine.initFromInventTable(InventTable::find(PurchLine.ItemId));
    PurchLine.PurchQty  = etgElevatorReceipt.DockageWeight;
    PurchLine.PurchReceivedNow = PurchLine.PurchQty;

    InventTable InventTableItem;
    WMSLocation location;

    InventTableItem = InventTable::find(etgElevatorReceipt.DockageGrain);
    inventdimLoc.InventSizeId   = InventTableItem.StandardInventSizeId;
    inventdimLoc.InventColorId  = InventTableItem.StandardInventColorId;
    inventdimLoc.InventStyleId  = InventTableItem.StandardInventStyleId;
    inventdimLoc.configId       = InventTableItem.StandardConfigId;
    if(etgScaleTicketTable.PrimaryBIN)
    {
        //container binValues = str2con(etgScaleTicketTable.BIN,';');
        select firstonly location where location.wMSLocationId == etgScaleTicketTable.PrimaryBIN;
        InventLocation inventlocation   = InventLocation::find(location.inventLocationId);
        inventdimLoc.InventSiteId       = inventlocation.InventSiteId;
        inventdimLoc.InventLocationId   =  inventlocation.InventLocationId;
        inventdimLoc.wMSLocationId      = location.wMSLocationId;
    }
    else
    {
        inventdimLoc.InventSiteId       = ETGCanadaParameters::find().SiteForZeroValuePo;
        inventdimLoc.InventLocationId   =  ETGCanadaParameters::find().WareHouseForZeroValuePo;
        select firstonly location where location.inventLocationId == inventdimLoc.InventLocationId;
        inventdimLoc.wMSLocationId      = location.wMSLocationId;
    }

    InventDim inventdim     = InventDim::findOrCreate(inventdimLoc);
    PurchLine.InventDimId   = inventdim.inventDimId;
    PurchLine.PurchPrice = 0;
    PurchLine.QtyOrdered = PurchLine.PurchQty;
    PurchLine.DefaultDimension = _agreementLine.DefaultDimension;
    PurchLine.createLine(true, true, true, true, true, true);
}

/// <summary>
/// Create purchline for splits item
/// </summary>
/// <param name = "Purchtable"></param>
/// <param name = "_agreementLine"></param>
/// <param name = "etgElevatorReceipt"></param>
public void createSplitsItemLine(PurchTable Purchtable,ETGElevatorReceiptTable etgElevatorReceipt, ETGScaleTicketTable etgScaleTicketTable,AgreementLine _agreementLine)
{
    ETGElevatorReceiptSplitsItemTable etgElevatorReceiptSplitsItemTable;

    while select etgElevatorReceiptSplitsItemTable
        where etgElevatorReceiptSplitsItemTable.ElevatorReceiptNumber == etgElevatorReceipt.ElevatorReceiptNumber
    {
        PurchLine PurchLine;
        InventDim inventdimLoc;
        PurchLine.PurchId = Purchtable.PurchId;

        PurchLine.initFromPurchTable(Purchtable);
        //purchLine.initFromAgreementLine(_agreementLine);
        PurchLine.ItemId    = etgElevatorReceiptSplitsItemTable.ItemId;
        PurchLine.initFromInventTable(InventTable::find(PurchLine.ItemId));
        PurchLine.PurchQty  =  (etgElevatorReceipt.GrainUnloadedWeight * etgElevatorReceiptSplitsItemTable.SplitsPercentage ) / 100;
        PurchLine.PurchReceivedNow = PurchLine.PurchQty;

        InventTable InventTableItem;
        WMSLocation location;

        InventTableItem = InventTable::find(etgElevatorReceiptSplitsItemTable.ItemId);
        inventdimLoc.InventSizeId   = InventTableItem.StandardInventSizeId;
        inventdimLoc.InventColorId  = InventTableItem.StandardInventColorId;
        inventdimLoc.InventStyleId  = InventTableItem.StandardInventStyleId;
        inventdimLoc.configId   = InventTableItem.StandardConfigId;

        if(etgScaleTicketTable.PrimaryBIN)
        {
            //container binValues = str2con(etgScaleTicketTable.BIN,';');

            select firstonly location where location.wMSLocationId == etgScaleTicketTable.PrimaryBIN;
            InventLocation inventlocation   = InventLocation::find(location.inventLocationId);
            inventdimLoc.InventSiteId       = inventlocation.InventSiteId;
            inventdimLoc.InventLocationId   =  inventlocation.InventLocationId;
            inventdimLoc.wMSLocationId      = location.wMSLocationId;
        }
        else
        {
            inventdimLoc.InventSiteId       = ETGCanadaParameters::find().SiteForZeroValuePo;
            inventdimLoc.InventLocationId   =  ETGCanadaParameters::find().WareHouseForZeroValuePo;
            select firstonly location where location.inventLocationId == inventdimLoc.InventLocationId;
            inventdimLoc.wMSLocationId      = location.wMSLocationId;
        }

        InventDim inventdim = InventDim::findOrCreate(inventdimLoc);
        PurchLine.InventDimId = inventdim.inventDimId;
        PurchLine.PurchPrice = 0;
        PurchLine.QtyOrdered = PurchLine.PurchQty;
        PurchLine.DefaultDimension = _agreementLine.DefaultDimension;
        PurchLine.createLine(true, true, true, true, true, true);
    }
}

/// <summary>
/// Ammendment of PO in default entity 
/// </summary>
public void clicked()
{
    super();

    if(Box::okCancel('@ETG_New:AmendmentOfPO',DialogButton::Cancel,'Confirm'))
    {
        NumberSeq               numberSeq;
        Purchtable              Purchtable;
        PurchLine               PurchLine;
        PurchFormLetter         purchFormLetter;
        AgreementLine           _agreementLine;
        ETGElevatorReceiptTable etgElevatorReceipt = ETGElevatorReceiptTable_ds.cursor();
        ETGScaleTicketTable     etgScaleTicketTable = ETGScaleTicketTable::findFromScaleTicketNumber(etgElevatorReceipt.scaleticketreferenceNumber);
        InventDim               inventdimLoc;
        DataAreaId              CurrentCompany = curExt();

        changeCompany(ETGCanadaParameters::find().DefaultEntityForDocuments)
        {
            PurchAgreementHeaderHistory     agreementHeaderHistory;
            ETG_PurchaseAgreementHeader     purchAgreementHeaderTrade;
            SalesAgreementHeader            salesAgreementHeader;
            SalesTable                      salesTable;
            PurchAgreementHeader            purchAgreementHeader = PurchAgreementHeader::findByAgreementId(etgScaleTicketTable.RefPurchAgreementNum);
            VendTable                       vendTable               = VendTable::find(purchAgreementHeader.VendAccount);

            select firstonly _agreementLine
                where _agreementLine.Agreement == purchAgreementHeader.RecId
                && _agreementLine.LineNumber == etgElevatorReceipt.AgreementLineNum;

            inventdimLoc = InventDim::find(_agreementLine.InventDimId);

            if(_agreementLine.RecId)
            {
                if(_agreementLine.quantityRemainingRelease() < etgElevatorReceipt.GrainUnloadedWeight)
                {
                    throw Error(strFmt("@ETG_New:PurchaseAgreementQtyValidation",_agreementLine.quantityRemainingRelease(),_agreementLine.ItemId));
                }

                ttsbegin;
                ///Create purchTable
                numberSeq = NumberSeq::newGetNum(PurchParameters::numRefPurchId());
                numberSeq.used();
                Purchtable.PurchId = numberSeq.num();
                Purchtable.initValue();
                purchTable.OrderAccount = purchAgreementHeader.VendAccount;
                purchTable.initFromVendTable(vendTable);
                purchTable.initFromPurchAgreementHeader(purchAgreementHeader,true,true);
                purchTable.ETGElevatorReceiptNumber       = etgElevatorReceipt.ElevatorReceiptNumber;
                purchTable.ETGERNEntity = CurrentCompany;

                select firstonly ConfirmationNumber,PurchNumberSequence from agreementHeaderHistory
                    order by agreementHeaderHistory.ConfirmationNumber desc
                        where agreementHeaderHistory.PurchNumberSequence == purchAgreementHeader.PurchNumberSequence
                join purchAgreementHeaderTrade
                    where purchAgreementHeaderTrade.PurchAgreementId == agreementHeaderHistory.PurchNumberSequence;

                ETG_ReleaseOrder::createPurchTrade(purchTable.PurchId, purchAgreementHeaderTrade);

                purchTable.ETG_AgreementConfirmationVersion = purchAgreementHeader.PurchNumberSequence + "-" + agreementHeaderHistory.ConfirmationNumber;
                //purchTable.MatchingAgreement = purchAgreementHeader.RecId;
                purchTable.DefaultDimension = purchAgreementHeader.DefaultDimension;
                if (!Purchtable.validateWrite())
                {
                    throw Exception::Error;
                }
                Purchtable.insert();

                ///Create purchLine for grain received
                PurchLine.PurchId = Purchtable.PurchId;
                PurchLine.ItemId = _agreementLine.ItemId;
                PurchLine.initFromPurchTable(Purchtable);

                purchLine.initFromAgreementLine(_agreementLine);
                PurchLine.PurchQty      = etgElevatorReceipt.GrainUnloadedWeight;
                PurchLine.LineAmount    = PurchLine.calcLineAmount(PurchLine.PurchQty);
                purchLine.initFromInventTable(InventTable::find(PurchLine.ItemId));

                //CS, DLT, SB, updating Agreement Header & creating SO for release
                if(purchAgreementHeader)
                {
                    AgreementLineQuantityCommitment     AgreementLineDerived = _agreementLine as AgreementLineQuantityCommitment;
                    ttsbegin;
                    purchAgreementHeader.selectForUpdate(true);
                    if(AgreementLineDerived.CommitedQuantity == purchLine.PurchQty)
                    {
                        purchAgreementHeader.ETG_TradingStatusPurch = ETG_TradingStatus::Released;
                    }
                    else
                    {
                        purchAgreementHeader.ETG_TradingStatusPurch = ETG_TradingStatus::PartiallyReleased;
                    }

                    purchAgreementHeader.ETG_DocumentStatusPurch = ETG_DocumentStatus::Order;
                    purchAgreementHeader.doUpdate();       
                    ttscommit;
                }
                if(purchAgreementHeader.ETG_SalesAgreementIdTP && !purchTable.ETG_TPSalesId)
                {
                    ttsbegin;
                    select firstonly * from salesAgreementHeader
                        where salesAgreementHeader.SalesNumberSequence == purchAgreementHeader.ETG_SalesAgreementIdTP;

                    if(salesAgreementHeader)
                    {
                        salesTable = ETG_ReleaseOrder::createSalesTable(salesAgreementHeader,purchTable.PurchId);

                        salesAgreementHeader.selectForUpdate(true);
                        salesAgreementHeader.ETG_TradingStatusSales  = purchAgreementHeader.ETG_TradingStatusPurch;
                        salesAgreementHeader.ETG_DocumentStatusSales = purchAgreementHeader.ETG_DocumentStatusPurch;
                        salesAgreementHeader.doUpdate();
                    }

                    if( salesTable.SalesId)
                    {
                        purchTable.selectForUpdate(true);
                        purchTable.ETG_TPSalesId         = salesTable.SalesId;
                        purchTable.ETG_IsThirdParty      = NoYes::Yes;
                        Purchtable.doUpdate();
                    }
                    ttscommit;
                }
                //CE, DLT, SB

                PurchLine.createLine(true, true, true, true, true, false);

                //Rate card line for agreement line item
                ETGRateCardMaster etgRateCardMaster;

                Select firstonly etgRateCardMaster
                    where etgRateCardMaster.ItemId == _agreementLine.ItemId
                    && etgRateCardMaster.RefRecId == _agreementLine.RecId;

                if(!etgRateCardMaster)
                {
                    this.createRatecardLines(etgElevatorReceipt,purchAgreementHeader,inventdimLoc,_agreementLine);
                }

                ttscommit;

                //Auto apply rate card
                try
                {
                    ttsbegin;
                    ETGElevatorReceiptRateCardApplyHelper::autoApplyRateCardOnPurchOrder(PurchLine,_agreementLine);

                    purchFormLetter = PurchFormLetter::construct(DocumentStatus::PurchaseOrder);
                    PurchaseOrderId purchOrderDocNum = strFmt('%1-%2', Purchtable.PurchId, VendPurchOrderJour::numberOfPurchaseOrderVersions(Purchtable)+1);
                    purchFormLetter.update(Purchtable, purchOrderDocNum);
                    ttscommit;
                }
                catch(Exception::Error)
                {
                    ttsabort;
                    warning("Auto rate card apply failed.");
                }

                info(strFmt('@ETG_New:PurchaseOrderCreatedDefaultEntity',Purchtable.PurchId,Purchtable.DataAreaId));
                changecompany(CurrentCompany)
                {
                    ttsbegin;
                    etgElevatorReceipt.selectForUpdate();
                    etgElevatorReceipt.ETGElevatorReceiptStatus = ETGElevatorReceiptStatus::POCreated;
                    etgElevatorReceipt.PONumberInDefaultEntity = Purchtable.PurchId;
                    etgElevatorReceipt.update();
                    ttscommit;
                }
            }
        }
    }
    ETGElevatorReceiptTable_ds.research(true);
    ETGElevatorReceiptTable_ds.refresh();
}

public void createRatecardLines(ETGElevatorReceiptTable etgElevatorReceipt,PurchAgreementHeader purchAgreementHeader,InventDim InventDimLoc,AgreementLine _agreementLine)
{
    ETGRateCardMaster rateCardMaster;
    InventTable inventTable;
    AgreementLineQuantityCommitment lineQtyCommittment;

    inventTable = InventTable::find(_agreementLine.ItemId);
    lineQtyCommittment = AgreementLineQuantityCommitment::find(_agreementLine.RecId);

    rateCardMaster.clear();
    rateCardMaster.RateCardId = NumberSeq::newGetNum(PurchParameters::numRefRateCardId()).num();
    rateCardMaster.ItemId = inventTable.ItemId;
    rateCardMaster.SubCommodity = inventTable.ETGSubCommodity;
    rateCardMaster.ProductName = inventTable.itemName();
    rateCardMaster.ModuleSalesPurch = ModuleSalesPurch::Purch;
    rateCardMaster.VendAccount = purchAgreementHeader.VendAccount;
    rateCardMaster.VendName = purchAgreementHeader.vendName();
    rateCardMaster.Qty      = lineQtyCommittment.CommitedQuantity;
    rateCardMaster.Price    = lineQtyCommittment.PricePerUnit;
    rateCardMaster.LineNumber = _agreementLine.LineNumber;
    rateCardMaster.configId = inventTable.StandardConfigId;
    rateCardMaster.InventSizeId = inventTable.StandardInventSizeId;
    rateCardMaster.InventColorId = inventTable.StandardInventColorId;
    rateCardMaster.InventStyleId = inventTable.StandardInventStyleId;
    rateCardMaster.RefRecId        = _agreementLine.RecId;
    rateCardMaster.insert();

}

/// <summary>
///
/// </summary>
public void lookup()
{
    //super();
    ETGElevatorReceiptTable elevatorReceiptTable = ETGElevatorReceiptTable_ds.cursor();
    if(!elevatorReceiptTable.ReceiptDate)
    {
        warning("@ETG_New:ScaleTicketMessage");
        return;
    }

    Query query = new Query();
    QueryBuildDataSource queryBuildDataSource;
    QueryBuildRange queryBuildRange;
    SysTableLookup sysTableLookup = SysTableLookup::newParameters(tableNum(ETGScaleTicketTable), this);

    sysTableLookup.addLookupField(fieldNum(ETGScaleTicketTable,ScaleTicketNumber));
    queryBuildDataSource = query.addDataSource(tableNum(ETGScaleTicketTable));

    if(elevatorReceiptTable.ReceiptDate)
    {
        queryBuildRange = queryBuildDataSource.addRange(fieldNum(ETGScaleTicketTable, ScaleDate));
        queryBuildRange.value(queryValue(elevatorReceiptTable.ReceiptDate));

    }

    sysTableLookup.parmQuery(query);
    sysTableLookup.performFormLookup();
}

/// <summary>
///
/// </summary>
/// <returns></returns>
public boolean modified()
{
    boolean ret;

    ret = super();

    if(ret)
    {
        ETGElevatorReceiptTable etgElevatorreceiptTableLocal;

        select firstonly etgElevatorreceiptTableLocal
        where etgElevatorreceiptTableLocal.ScaleTicketReferenceNumber == ETGElevatorReceiptTable.ScaleTicketReferenceNumber;

        if(etgElevatorreceiptTableLocal)
        {
            throw error("@ETG_New:OneScaleTicketOnlyOnce");
            ret = false;
        }

        ETGScaleTicketTable etgScaleTicketTable = ETGScaleTicketTable::findFromScaleTicketNumber(ETGElevatorReceiptTable.ScaleTicketReferenceNumber);

        if(etgScaleTicketTable)
        {
            ETGElevatorReceiptTable.GrossWeight = etgScaleTicketTable.Gross;
            ETGElevatorReceiptTable.VehicleWeight = etgScaleTicketTable.Tare;
            ETGElevatorReceiptTable.GrainUnloadedWeight = etgScaleTicketTable.Net;
            ETGElevatorReceiptTable.NetWeight = etgScaleTicketTable.Net;
            PurchAgreementHeader purchAgreementHeader = PurchAgreementHeader::findByAgreementId(etgScaleTicketTable.RefPurchAgreementNum,ETGCanadaParameters::find().DefaultEntityForDocuments);
            ETGElevatorReceiptTable.ReceiptReference = purchAgreementHeader.VendAccount + " : " + purchAgreementHeader.vendName();
        }
    }

    return ret;
}

