/// <summary>
///
/// </summary>
/// <returns></returns>
public boolean modified()
{
    boolean ret;

    ret = super();

    ETGElevatorReceiptTable.DockageWeight = ETGElevatorReceiptTable.GrainUnloadedWeight * ( ETGElevatorReceiptTable.DockagePercentage / 100);
    ETGElevatorReceiptTable.NetWeight = ETGElevatorReceiptTable.GrainUnloadedWeight - ETGElevatorReceiptTable.DockageWeight - ETGElevatorReceiptTable.SplitsWeight;

    return ret;
}

/// <summary>
///
/// </summary>
/// <returns></returns>
public boolean modified()
{
    boolean ret;

    ret = super();

    ETGElevatorReceiptTable.SplitsWeight = ETGElevatorReceiptTable.GrainUnloadedWeight * ( ETGElevatorReceiptTable.SplitsPercentage / 100);
    ETGElevatorReceiptTable.NetWeight = ETGElevatorReceiptTable.GrainUnloadedWeight - ETGElevatorReceiptTable.DockageWeight - ETGElevatorReceiptTable.SplitsWeight;

    return ret;
}

/// <summary>
///
/// </summary>
public void jumpRef()
{
    super();
    PurchTable purchTable;
    DataAreaId targetCompany;

    select firstOnly crossCompany purchTable
        where purchTable.PurchId == ETGElevatorReceiptTable.PONumberInDefaultEntity;

    if (purchTable)
    {
        targetCompany = purchTable.DataAreaId;

        changeCompany(targetCompany)
        {
            Args args = new Args();
            args.record(purchTable);
            new MenuFunction(menuItemDisplayStr(PurchTable), MenuItemType::Display).run(args);
        }
    }

}
